#include <iostream>
#include <unordered_set>

struct ListNode {
    int val;
    ListNode* next;

    ListNode(int val) : val(val), next(nullptr) {}
};

class Solution { 
public:
bool hasCycle(ListNode* head) { 
	if (head == nullptr) return false; 
	ListNode* slow = head;
	if (head->next == nullptr) return false;
	ListNode* fast = head->next;
	 while (fast) { 
		 slow = slow->next;
		 fast = fast->next->next;
		 if (slow == fast) { 
			 return true; 
		 } 
	}
	return false;
}
};

int main() { 
	std::ios_base::sync_with_stdio(false);
	std::cin.tie(nullptr);

	int n;
	std::cin >> n;
	int val;
	ListNode* head = nullptr;
	ListNode* curr = nullptr;
	std::cin >> val;
	curr = new ListNode(val);
	head = curr;
	for (int i = 0; i < n - 1; ++i) {
		std::cin >> val;
		curr->next = new ListNode(val);
		curr = curr->next;
	}
	int cycle_node;
	if (std::cin >> cycle_node) {
		curr = head;
		for (int i = 0; i < cycle_node - 1; ++i) {
			curr = curr->next;
		}
		curr->next = head;
	}

	Solution solution;
	bool result = solution.hasCycle(head);
	std::cout << (result ? "True" : "False") << "\n";
	return 0;
}
